// Fold (X / C) << N | (X % C) -> (X / C) * (2^N - C) + X when disjoint.
// This reassociates the expression to reduce the number of operations.
// Since X = (X / C) * C + (X % C), we have:
// (X / C) * 2^N + (X % C) = (X / C) * 2^N + X - (X / C) * C
//                         = (X / C) * (2^N - C) + X
{
  Value *X, *Div;
  const APInt *DivC, *ShAmt;
  if (match(&I, m_DisjointOr(m_OneUse(m_Shl(m_CombineAnd(m_UDiv(m_Value(X), m_APInt(DivC)),
                                                         m_Value(Div)),
                                             m_APInt(ShAmt))),
                             m_URem(m_Specific(X), m_APInt(DivC))))) {
    // Check that 2^N >= C to ensure the shift doesn't lose information.
    APInt Pow2 = APInt::getOneBitSet(ShAmt->getBitWidth(), ShAmt->getZExtValue());
    if (Pow2.uge(*DivC)) {
      APInt MulC = Pow2 - *DivC;
      Value *NewMul = Builder.CreateMul(Div, ConstantInt::get(Ty, MulC));
      return BinaryOperator::CreateAdd(NewMul, X);
    }
  }
}
```

